import { _decorator, Component, director, Node, Label, Button, ScrollView, Prefab, instantiate } from 'cc';
import { GameManager } from '../Core/GameManager';

const { ccclass, property } = _decorator;

@ccclass('BagScene')
export class BagScene extends Component {
    @property(Button)
    backBtn: Button = null;
    
    @property(ScrollView)
    itemScrollView: ScrollView = null;
    
    @property(Node)
    itemPrefab: Node = null;
    
    @property(Label)
    capacityLabel: Label = null;
    
    private items = [
        { id: 'incense_sticks', name: '线香', type: 'material', desc: '供奉用的线香', icon: 'incense_sticks' },
        { id: 'candles', name: '蜡烛', type: 'material', desc: '供奉用的蜡烛', icon: 'candles' },
        { id: 'gold_paper', name: '金纸', type: 'material', desc: '供奉用的金纸', icon: 'gold_paper' },
        { id: 'fruits', name: '供果', type: 'material', desc: '供奉用的水果', icon: 'fruits' },
        { id: 'wood_sword', name: '桃木剑', type: 'equipment', desc: '攻击+10', icon: 'sword' },
        { id: 'bronze_mirror', name: '青铜镜', type: 'equipment', desc: '防御+5', icon: 'mirror' },
        { id: 'health_pill', name: '回气丹', type: 'consumable', desc: '恢复50点法力', icon: 'pill' }
    ];
    
    onLoad() {
        this.backBtn.node.on(Button.EventType.CLICK, this.onBack, this);
    }
    
    start() {
        this.updateBag();
    }
    
    updateBag() {
        const player = GameManager.getInstance().playerData;
        const content = this.itemScrollView.content;
        content.removeAllChildren();
        
        let itemCount = 0;
        
        for (const item of this.items) {
            const quantity = player.getCurrency(item.id);
            if (quantity > 0 || item.type === 'equipment') {
                itemCount++;
                const itemNode = instantiate(this.itemPrefab);
                
                itemNode.getChildByName('NameLabel').getComponent(Label).string = item.name;
                itemNode.getChildByName('CountLabel').getComponent(Label).string = `x${quantity}`;
                itemNode.getChildByName('DescLabel').getComponent(Label).string = item.desc;
                
                const useBtn = itemNode.getChildByName('UseBtn').getComponent(Button);
                useBtn.node.on(Button.EventType.CLICK, () => this.onUseItem(item.id), this);
                
                content.addChild(itemNode);
            }
        }
        
        this.capacityLabel.string = `${itemCount}/50`;
    }
    
    onUseItem(itemId: string) {
        const player = GameManager.getInstance().playerData;
        
        if (itemId === 'health_pill') {
            if (player.getCurrency('health_pill') > 0) {
                player.costCurrency('health_pill', 1);
                player.addCurrency('mana', 50);
                this.updateBag();
                // 显示使用成功
            }
        } else if (itemId === 'wood_sword' || itemId === 'bronze_mirror') {
            // 装备物品
            // 显示装备成功
        }
    }
    
    onBack() {
        director.loadScene('MainScene');
    }
}
